mapper.select:
SELECT BUYER_CD, REQ_NUM, REQ_SEQ
  FROM STOCETDT
 WHERE GATE_CD  = #{ses.gateCd}
   AND ENTRST_COMP_CD = #{BUYER_CD}
   AND APP_DOC_NUM    = #{APP_DOC_NUM}
   AND APP_DOC_CNT    = #{APP_DOC_CNT}
   AND DEL_FLAG = '0'

mapper.update:
UPDATE STOCETDT SET
      MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , APP_STATUS  = #{SIGN_STATUS}

    , APP_DATE    = SYSDATE

 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND REQ_NUM  = #{REQ_NUM}
   AND REQ_SEQ  = #{REQ_SEQ}
